  (void)routing_logits; (void)routing_bias; (void)hidden_states_fp8; (void)hidden_states_scale;
  (void)gemm1_w_fp8; (void)gemm1_w_scale; (void)gemm2_w_fp8; (void)gemm2_w_scale;
  (void)local_expert_offset; (void)routed_scaling_factor; (void)output; (void)T; (void)stream;
