// Expose kernels for main.cpp (compile unit linkage)
extern "C" void moe_dispatch(
    const float* routing_logits,
    const at::BFloat16* routing_bias,
    const uint8_t* hidden_states_fp8,
    const float* hidden_states_scale,
    const uint8_t* gemm1_w_fp8,
    const float* gemm1_w_scale,
    const uint8_t* gemm2_w_fp8,
    const float* gemm2_w_scale,
    int32_t local_expert_offset,
    float routed_scaling_factor,
    uint16_t* topk_idx,
    float* topk_w,
    float* out_fp32,
    at::BFloat16* out_bf16,
    int32_t T,
    cudaStream_t stream)
{
  // Routing
  routing_topk8_kernel<<<dim3((unsigned)T,1,1), dim3(256,1,1), 0, stream>>>(
      routing_logits, routing_bias, topk_idx, topk_w, T, routed_scaling_factor);
  CUDA_CHECK(cudaGetLastError());

  // Zero output fp32
  CUDA_CHECK(cudaMemsetAsync(out_fp32, 0, sizeof(float) * (size_t)T * kH, stream));

  // MoE local accumulate: grid (T,8,56), block 128 threads
  dim3 grid((unsigned)T, (unsigned)kTopK, (unsigned)kHiddenBlocks);
  moe_local_accum_fp32_kernel<<<grid, dim3(128,1,1), 0, stream>>>(
      hidden_states_fp8, hidden_states_scale,
      gemm1_w_fp8, gemm1_w_scale,
      gemm2_w_fp8, gemm2_w_scale,
      topk_idx, topk_w, local_expert_offset,
      out_fp32, T);
  CUDA_CHECK(cudaGetLastError());

  // Cast to bf16
  int64_t n = (int64_t)T * kH;
  int threads = 256;
  int blocks = (int)((n + threads - 1) / threads);
  cast_fp32_to_bf16_kernel<<<blocks, threads, 0, stream>>>(out_fp32, out_bf16, n);
  CUDA_CHECK(cudaGetLastError());
}

