static void check_cuda(const torch::Tensor& t, const char* name) {
  if (!t.defined()) {
    std::ostringstream oss; oss << name << " is undefined";
    throw std::runtime_error(oss.str());
  }
  if (!t.is_cuda()) {
    std::ostringstream oss; oss << name << " must be a CUDA tensor";
    throw std::runtime_error(oss.str());
  }
  if (!t.is_contiguous()) {
    std::ostringstream oss; oss << name << " must be contiguous";
    throw std::runtime_error(oss.str());
  }
}

static void check_shape(const torch::Tensor& t, std::vector<int64_t> expect, const char* name) {
  if ((int)t.dim() != (int)expect.size()) {
    std::ostringstream oss; oss << name << " dim mismatch. expected " << expect.size()
                               << " got " << t.dim();
    throw std::runtime_error(oss.str());
  }
  for (int i = 0; i < (int)expect.size(); ++i) {
    if (expect[i] >= 0 && t.size(i) != expect[i]) {
      std::ostringstream oss; oss << name << " shape mismatch at dim " << i
                                 << ". expected " << expect[i] << " got " << t.size(i);
      throw std::runtime_error(oss.str());
    }
  }
}

torch::Tensor run(
    torch::Tensor routing_logits,          // [T,256] float32
    torch::Tensor routing_bias,            // [256] bfloat16
    torch::Tensor hidden_states,           // [T,7168] float8 e4m3fn
    torch::Tensor hidden_states_scale,     // [56,T] float32
    torch::Tensor gemm1_weights,           // [32,4096,7168] float8 e4m3fn
    torch::Tensor gemm1_weights_scale,     // [32,32,56] float32
    torch::Tensor gemm2_weights,           // [32,7168,2048] float8 e4m3fn
    torch::Tensor gemm2_weights_scale,     // [32,56,16] float32
    int64_t local_expert_offset,
    double routed_scaling_factor)
{
  check_cuda(routing_logits, "routing_logits");
  check_cuda(routing_bias, "routing_bias");
  check_cuda(hidden_states, "hidden_states");
  check_cuda(hidden_states_scale, "hidden_states_scale");
  check_cuda(gemm1_weights, "gemm1_weights");
  check_cuda(gemm1_weights_scale, "gemm1_weights_scale");
  check_cuda(gemm2_weights, "gemm2_weights");
  check_cuda(gemm2_weights_scale, "gemm2_weights_scale");

  if (routing_logits.scalar_type() != torch::kFloat32)
    throw std::runtime_error("routing_logits must be float32");
  if (routing_bias.scalar_type() != torch::kBFloat16)
    throw std::runtime_error("routing_bias must be bfloat16");
  if (hidden_states.scalar_type() != torch::kFloat8E4M3FN)
    throw std::runtime_error("hidden_states must be float8_e4m3fn");
  if (hidden_states_scale.scalar_type() != torch::kFloat32)
    throw std::runtime_error("hidden_states_scale must be float32");
  if (gemm1_weights.scalar_type() != torch::kFloat8E4M3FN)
    throw std::runtime_error("gemm1_weights must be float8_e4m3fn");
  if (gemm1_weights_scale.scalar_type() != torch::kFloat32)
    throw std::runtime_error("gemm1_weights_scale must be float32");
  if (gemm2_weights.scalar_type() != torch::kFloat8E4M3FN)
    throw std::runtime_error("gemm2_weights must be float8_e4m3fn");
  if (gemm2_weights_scale.scalar_type() != torch::kFloat32)
    throw std::runtime_error("gemm2_weights_scale must be float32");

  int64_t T = routing_logits.size(0);
  check_shape(routing_logits, {T, kEGlobal}, "routing_logits");
  check_shape(routing_bias, {kEGlobal}, "routing_bias");
  check_shape(hidden_states, {T, kH}, "hidden_states");
  check_shape(hidden_states_scale, {kHiddenBlocks, T}, "hidden_states_scale");
  check_shape(gemm1_weights, {kELocal, kG1Out, kH}, "gemm1_weights");
  check_shape(gemm1_weights_scale, {kELocal, kG1OutBlocks, kHiddenBlocks}, "gemm1_weights_scale");
  check_shape(gemm2_weights, {kELocal, kH, kI}, "gemm2_weights");
  check_shape(gemm2_weights_scale, {kELocal, kHiddenBlocks, kInterBlocks}, "gemm2_weights_scale");

  if (T <= 0) throw std::runtime_error("seq_len must be > 0");
  if (local_expert_offset < INT32_MIN || local_expert_offset > INT32_MAX)
    throw std::runtime_error("local_expert_offset out of int32 range");

  auto opts_bf16 = torch::TensorOptions().device(hidden_states.device()).dtype(torch::kBFloat16);
  auto out = torch::empty({T, kH}, opts_bf16);

  // Temp buffers
  auto opts_u16 = torch::TensorOptions().device(hidden_states.device()).dtype(torch::kUInt16);
  auto opts_f32 = torch::TensorOptions().device(hidden_states.device()).dtype(torch::kFloat32);
  auto topk_idx = torch::empty({T, kTopK}, opts_u16);
  auto topk_w   = torch::empty({T, kTopK}, opts_f32);
  auto out_fp32 = torch::empty({T, kH}, opts_f32);

  cudaStream_t stream = at::cuda::getDefaultCUDAStream();

  moe_dispatch(
      routing_logits.data_ptr<float>(),
      (const at::BFloat16*)routing_bias.data_ptr<at::BFloat16>(),
      (const uint8_t*)hidden_states.data_ptr<uint8_t>(),
      hidden_states_scale.data_ptr<float>(),
      (const uint8_t*)gemm1_weights.data_ptr<uint8_t>(),
      gemm1_weights_scale.data_ptr<float>(),
      (const uint8_t*)gemm2_weights.data_ptr<uint8_t>(),
      gemm2_weights_scale.data_ptr<float>(),
      (int32_t)local_expert_offset,
      (float)routed_scaling_factor,
      topk_idx.data_ptr<uint16_t>(),
      topk_w.data_ptr<float>(),
      out_fp32.data_ptr<float>(),
      (at::BFloat16*)out.data_ptr<at::BFloat16>(),
      (int32_t)T,
      stream);

  CUDA_CHECK(cudaGetLastError());
  CUDA_CHECK(cudaStreamSynchronize(stream));

  return out;
}

